SELECT dg.gb_dg_goods_name AS gbDgGoodsName, dg.gb_dg_nx_father_img AS gbDgNxFatherImg, dg.gb_dg_goods_standardname AS gbDgGoodsStandardname, gsr.gb_dgsr_gb_dis_goods_id AS gbDistributerGoodsId, ROUND(SUM(gb_dgsr_produce_subtotal), 1) AS goodsProduceTotal FROM gb_department_goods_stock_reduce gsr LEFT JOIN gb_distributer_goods dg ON dg.gb_distributer_goods_id = gsr.gb_dgsr_gb_dis_goods_id WHERE 1=1
AND gsr.gb_dgsr_date >= #{startDate}
AND gsr.gb_dgsr_date <= #{stopDate}
AND gsr.gb_dgsr_gb_distributer_id = #{disId}
GROUP BY gsr.gb_dgsr_gb_dis_goods_id, dg.gb_dg_goods_name ORDER BY goodsProduceTotal DESC LIMIT 10

SELECT dg.gb_dg_goods_name AS gbDgGoodsName, dg.gb_dg_nx_father_img AS gbDgNxFatherImg, dg.gb_dg_goods_standardname AS gbDgGoodsStandardname, gsr.gb_dgsr_gb_dis_goods_id AS gbDistributerGoodsId, gb_dgsr_gb_dis_goods_id AS disGoodsId, ROUND(SUM(gb_dgsr_loss_subtotal), 1) AS goodsLossTotal FROM gb_department_goods_stock_reduce gsr LEFT JOIN gb_distributer_goods dg ON dg.gb_distributer_goods_id = gsr.gb_dgsr_gb_dis_goods_id WHERE 1=1
AND gb_dgsr_date >= #{startDate}
AND gb_dgsr_date <= #{stopDate}
AND gsr.gb_dgsr_gb_distributer_id = #{disId}
GROUP BY gb_dgsr_gb_dis_goods_id ORDER BY goodsLossTotal DESC LIMIT 10

SELECT dg.gb_dg_goods_name AS gbDgGoodsName, dg.gb_dg_nx_father_img AS gbDgNxFatherImg, dg.gb_dg_goods_standardname AS gbDgGoodsStandardname, gsr.gb_dgsr_gb_dis_goods_id AS gbDistributerGoodsId, gb_dgsr_gb_dis_goods_id AS gbDistributerGoodsId,
ROUND(SUM(gb_dgsr_waste_subtotal), 1) AS goodsWasteTotal
FROM gb_department_goods_stock_reduce gsr LEFT JOIN gb_distributer_goods dg ON dg.gb_distributer_goods_id = gsr.gb_dgsr_gb_dis_goods_id WHERE 1=1
AND gb_dgsr_date >= #{startDate}
AND gb_dgsr_date <= #{stopDate}
AND gsr.gb_dgsr_gb_distributer_id = #{disId}
GROUP BY gb_dgsr_gb_dis_goods_id ORDER BY goodsWasteTotal DESC LIMIT 10

SELECT gb_dgsr_date AS date, ROUND(SUM(COALESCE(gb_dgsr_produce_subtotal, 0) + COALESCE(gb_dgsr_loss_subtotal, 0) + COALESCE(gb_dgsr_waste_subtotal, 0)), 1) AS goodsProduceTotal FROM gb_department_goods_stock_reduce WHERE 1=1
AND gb_dgsr_date >= #{startDate}
AND gb_dgsr_date <= #{stopDate}
AND gb_dgsr_gb_distributer_id = #{disId}
GROUP BY gb_dgsr_date ORDER BY goodsProduceTotal DESC LIMIT 10

SELECT
dg.*,
sr.first_date,
sr.last_date,
sr.record_count,
sr.total_cost_subtotal,
sr.total_produce_subtotal,
sr.total_loss_subtotal,
sr.total_waste_subtotal
FROM gb_distributer_goods AS dg

INNER JOIN (
SELECT
r.gb_dgsr_gb_dis_goods_id                   AS goodsId,
MIN(r.gb_dgsr_date)                         AS first_date,
MAX(r.gb_dgsr_date)                         AS last_date,
COUNT(*)                                    AS record_count,
ROUND(SUM(r.gb_dgsr_cost_subtotal), 1)      AS total_cost_subtotal,
ROUND(SUM(r.gb_dgsr_produce_subtotal), 1)   AS total_produce_subtotal,
ROUND(SUM(r.gb_dgsr_loss_subtotal), 1)      AS total_loss_subtotal,
ROUND(SUM(r.gb_dgsr_waste_subtotal), 1)     AS total_waste_subtotal
FROM gb_department_goods_stock_reduce r
JOIN gb_department d
ON d.gb_department_id = r.gb_dgsr_gb_department_id
WHERE 1=1


    AND r.gb_dgsr_date = #{date}



    AND d.gb_department_type = #{depType}



    AND r.gb_dgsr_gb_pur_goods_id = #{purGoodsId}


    AND r.gb_dgsr_gb_goods_inventory_type = #{inventoryType}


    AND r.gb_dgsr_type = #{equalType}


    AND r.gb_dgsr_gb_dis_goods_id = #{disGoodsId}


    AND r.gb_dgsr_stock_nx_distributer_id = #{nxDisId}


    AND r.gb_dgsr_gb_dis_goods_father_id = #{disGoodsFatherId}


    AND r.gb_dgsr_gb_dis_goods_grand_id = #{disGoodsGrandId}


    AND r.gb_dgsr_gb_dis_goods_great_id = #{disGoodsGreatId}


    AND r.gb_dgsr_gb_department_id = #{depId}


    AND r.gb_dgsr_gb_department_father_id = #{depFatherId}


    AND r.gb_dgsr_gb_department_father_id IN

        #{id}


GROUP BY r.gb_dgsr_gb_dis_goods_id
) AS sr
ON sr.goodsId = dg.gb_distributer_goods_id




        AND dg.gb_dg_distributer_id = #{disId}


        AND dg.gb_dg_pull_off = #{pull}


        AND dg.gb_dg_control_fresh = #{fresh}


        AND dg.gb_dg_is_self_control = #{isSelf}


        AND dg.gb_dg_nx_distributer_id = #{nxDisId}


        AND dg.gb_dg_nx_distributer_goods_id = #{nxDisGoodsId}


        AND dg.gb_dg_dfg_goods_father_id = #{dgFatherId}


        AND dg.gb_dg_nx_goods_id = #{goodsId}






        ORDER BY sr.total_cost_subtotal DESC


        ORDER BY sr.total_produce_subtotal DESC


        ORDER BY sr.total_loss_subtotal DESC


        ORDER BY sr.total_waste_subtotal DESC


        ORDER BY sr.total_cost_subtotal DESC




    LIMIT #{offset}, #{limit}

